
(function(){

function initIphone(){
  if(window.innerWidth < 900) return
  if(document.querySelector("#iphone17-container")) return
  

  

  /* CSS */
  if(!document.querySelector("#iphone-style")){
    const style=document.createElement("style")
    style.id="iphone-style"
    style.innerHTML=`


      .app-wrapper {
        display: flex;
        flex-direction: column;
        align-items: center;
        width: 72px; /* 略大于图标宽度 */
        gap: 5px;
      }
    
      #iphone17-container{
        position:fixed;
        top:80px;
        left:50px;
        width:420px;
        z-index:9999;
        cursor:move;
      }
      .iphone17{
        width:420px;
        height:860px;
        border-radius:60px;
        padding:12px;
        position:relative;
        overflow:hidden;
      }
      .dynamic-island{
        position:absolute;
        top:12px;
        left:35%;
        transform:translateX(-50%);
        width:100px;
        height:28px;
        background:#000;
        border-radius:20px;
        z-index:20;
        display:flex;
        align-items:center;
        justify-content:center;
        animation:islandBreath 10s ease-in-out infinite;
      }
      .island-core{
        width:100%;
        height:100%;
        background:#000;
        border-radius:20px;
        display:flex;
        align-items:center;
        justify-content:center;
        animation:islandBreath 10s ease-in-out infinite;
        color:#fff;
        font-size:10px;  /* 字体缩小 */
        cursor:pointer;
      }
      @keyframes islandBreath{
        0%{transform:scale(1);}
        50%{transform:scale(1.06);}
        100%{transform:scale(1);}
      }
      .iphone-screen{
        width:100%;
        height:100%;
        border-radius:40px;
        overflow:hidden;
        background:#000;
        cursor:grab;
        position:relative;
      }
      .photo-track{
        display:flex;
        height:100%;
        will-change:transform;
      }
      .photo-track img{
        width:100%;
        height:100%;
        object-fit:cover;
        flex-shrink:0;
        pointer-events:none;
        user-select:none;
      }
      #iphone-apps {
        position: absolute;
        top: 60px;
        left: 0;
        width: 100%;
        height: calc(100% - 60px);
        display: grid;
        grid-template-columns: repeat(4, 1fr);

        /* --- 修改这里 --- */
        grid-auto-rows: 110px; /* 从 90px 改为 110px，给文字腾地方 */
        grid-gap: 20px 10px;   /* 增加行与行之间的间距 */
        /* ---------------- */

        justify-items: center;
        align-items: start;
        z-index: 30;
        pointer-events: auto;
        padding: 20px 10px;    /* 增加顶部内边距，防止第一排太靠上 */
        box-sizing: border-box;
      }
      .app-name {
        color: #fff;
        font-size: 11px;
        text-align: center;
        width: 100%;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
        text-shadow: 0 1px 2px rgba(0,0,0,0.8);
        font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica;
      }
      .iphone-app-icon {
        width: 60px;
        height: 60px;
        border-radius: 15px;
        background-size: cover;
        background-position: center;
        cursor: pointer;
        transition: transform 0.2s;
        flex-shrink: 0;
      }
      .iphone-app-icon:hover{
        transform:scale(1.1);
      }
      /* 灵动岛小设置按钮 */
      .island-setting-button{
        width:20px;             /* 小一点 */
        height:20px;            /* 小一点 */
        border-radius:10px;     /* 完全圆形 */
        background:#000;        /* 和灵动岛一致 */
        display:flex;
        align-items:center;
        justify-content:center;
        color:#fff;
        font-size:10px;         /* 字体更小 */
        cursor:pointer;
        transition: transform 0.2s;
      }
      .island-setting-button:hover{
        transform:scale(1.1);
      }
      @media(max-width:900px){#iphone17-container{display:none;}}
    `;
    document.head.appendChild(style)
  }

  /* HTML */
  
  const container=document.createElement("div")
  container.id="iphone17-container"
  container.innerHTML=`
  
    <div class="iphone17">
      <div class="iphone-screen" id="iphoneScreen">
        <div class="dynamic-island"><div class="island-core" id="islandCore"></div></div>
        <div class="photo-track" id="iphoneTrack">
          <img src="/img/1.png">
          <img src="/img/IphoneWallpaper/1b91bebb485f60150dd7534b8ff800d5.jpg">
          <img src="/img/IphoneWallpaper/6c8c3da69f16da2457068e2a75e3459d.jpg">
          <img src="/img/IphoneWallpaper/08a6052bfb25955815fabdd4766e7b84.jpg">
          <img src="/img/IphoneWallpaper/49df65d51ae2ce90808c4322e089c72f.jpg">
          <img src="/img/IphoneWallpaper/awdawfaw.jpg">
          <img src="/img/IphoneWallpaper/bcf4a8a5373c27af341bc2a8b9b30724.jpg">
          <img src="/img/IphoneWallpaper/dcca0ec3274297321db423666a7ff807.jpg">
          <img src="/img/IphoneWallpaper/e1382f9744e5e0e6ec270013788dbe47.jpg">
          <img src="/img/IphoneWallpaper/eea99e48591b8fff17314e21f4ecebf4.jpg">
          <img src="/img/IphoneWallpaper/fb8c7c9bdc9eea223aca8dd1ebe682c7.jpg">
          <img src="/img/2.png">
          <img src="/img/3.png">
          <img src="/img/4.png">
          <img src="/img/5.png">
          <img src="/img/6.png">
          <img src="/img/7.png">
          <img src="/img/8.png">
          <img src="/img/9.png">
          <img src="/img/10.png">
          <img src="/img/11.png">
          <img src="/img/12.png">
          <img src="/img/13.png">
          <img src="/img/14.png">
          <img src="/img/15.png">
          <img src="/img/16.png">
          <img src="/img/17.png">
          <img src="/img/18.png">
          <img src="/img/19.png">
          <img src="/img/20.png">
      </di>
     </di>
  </di>
  `;
  document.body.appendChild(container);

  /* 图片轮播 */
  const screen=document.getElementById("iphoneScreen")
  const track=document.getElementById("iphoneTrack")
  const imgs=Array.from(track.children)
  imgs.forEach(img=> track.appendChild(img.cloneNode(true)))
  let position=0, velocity=0, dragging=false, startX=0
  screen.addEventListener("mousedown",(e)=>{
    if(e.target.closest(".iphone-app-icon")) return
    e.preventDefault()
    dragging=true
    startX=e.clientX
    screen.style.cursor="grabbing"
  })
  document.addEventListener("mouseup",()=>{ dragging=false; screen.style.cursor="grab"; })
  document.addEventListener("mousemove",(e)=>{
    if(!dragging) return
    let dx=e.clientX-startX
    position += dx
    velocity = dx * 0.4
    startX=e.clientX
  })
  function animate(){ position+=velocity; velocity*=0.92; const width=screen.offsetWidth; if(position<=-width*imgs.length) position=0; if(position>0) position=-width*imgs.length; track.style.transform="translateX("+position+"px)"; requestAnimationFrame(animate) }
  animate()
  let autoIndex=0
  setInterval(()=>{ if(dragging) return; const width=screen.offsetWidth; autoIndex++; position=-width*autoIndex; if(autoIndex>=imgs.length){ autoIndex=0; position=0;} },3000)

  /* 添加应用格子 */
  const appsContainer=document.createElement("div")
  appsContainer.id="iphone-apps"
  screen.appendChild(appsContainer)

  const apps=[
    // {name:"cc",icon:'',action:()=>open("/2025/09/14/Catsithfamily/")},
    {name:"设置",icon:'data:image/png;base64,',action:()=>enterIslandSettings()},
    {name:"食用提示",icon:"/img/touxiang.ico",action:()=>Knowlege()},
    {name:"破解软件",icon:'/img/AnimatedGIF.gif',action:()=>{BlogSettings()}},
    {name:"相册",icon:'data:image/png;base64,',action:()=>open("/2025/09/14/Catsithfamily/")},
    {name:"浏览器",icon:'data:image/png;base64,',action:()=>window.open("https://www.google.com","_blank")},
    {name:"微信",icon:'data:image/png;base64,',action:()=>open("/OtherPage/WechatPage")},
    {name:"支付宝",icon:"data:image/png;base64,"  ,action:()=>open("/OtherPage/AlipayPage")},
    {name:"币安",icon:'data:image/png;base64,',action:()=>open("/OtherPage/BinancePage")},
    {name:"钱包",icon:'data:image/png;base64,',action:()=>{WalletShake();Falldown()}},
    {name:"bilibili",icon:'data:image/jpeg;base64,',action:()=>open("https://space.bilibili.com/306956198")},
    {name:"Steam",icon:'data:image/png;base64,',action:()=>open("https://steamcommunity.com/id/jEseeP1nkman/")},
    
 
  ];

/* 找到这部分并替换 */
  /* 彻底替换这一段 */
  apps.forEach(app => {
      // 1. 创建父容器
      const appWrapper = document.createElement("div");
      appWrapper.className = "app-item-wrapper"; // 建议加个类名方便调试
      appWrapper.style.display = "flex";
      appWrapper.style.flexDirection = "column";
      appWrapper.style.alignItems = "center";
      appWrapper.style.justifyContent = "flex-start";
      appWrapper.style.cursor = "pointer";
      appWrapper.style.width = "100%";
      appWrapper.style.height = "100%"; // 撑满网格格子
  
      // 2. 创建图标
      const icon = document.createElement("div");
      icon.className = "iphone-app-icon";
      icon.style.backgroundImage = `url(${app.icon})`;
      icon.style.width = "60px";
      icon.style.height = "60px";
      icon.style.borderRadius = "14px"; // 苹果标准的圆角比
      icon.style.backgroundSize = "cover";
      icon.style.backgroundPosition = "center";
      icon.style.boxShadow = "0 4px 10px rgba(0,0,0,0.2)";
  
      // 3. 创建名字 (修复了你之前的截断问题)
      const nameLabel = document.createElement("div");
      nameLabel.innerText = app.name || "未命名"; 
      nameLabel.style.color = "#ffffff";
      nameLabel.style.fontSize = "12px";
      nameLabel.style.marginTop = "6px"; 
      nameLabel.style.textAlign = "center";
      nameLabel.style.width = "100%";
      // 增加投影，防止背景太亮看不清白字
      nameLabel.style.textShadow = "0px 1px 3px rgba(0,0,0,0.8)"; 
      nameLabel.style.pointerEvents = "none"; // 防止点击文字没反应
  
      // 4. 组装
      appWrapper.appendChild(icon);
      appWrapper.appendChild(nameLabel);
  
      // 5. 事件
      appWrapper.onclick = () => {
          if (typeof app.action === 'function') {
              app.action();
          }
      };
    
      // 6. 放入容器
      appsContainer.appendChild(appWrapper);
  });

  /* 灵动岛小设置按钮 */
  const islandCore=document.getElementById("islandCore")
  let islandSettingButton=null

  function enterIslandSettings(){
    appsContainer.style.display="none"
    if(!islandSettingButton){
      islandSettingButton=document.createElement("div")
      islandSettingButton.className="island-setting-button"
      islandSettingButton.innerText="⚙"
      islandCore.appendChild(islandSettingButton)

      islandSettingButton.addEventListener("click",()=>{
        appsContainer.style.display="grid"
        islandCore.removeChild(islandSettingButton)
        islandSettingButton=null
      })
    }
  }

  /* 手机拖动 */
  let phoneDrag=false, phOffsetX=0, phOffsetY=0
  container.addEventListener("mousedown",(e)=>{
    if(e.target.closest(".iphone-screen") || e.target.closest(".iphone-app-icon") || e.target.closest(".island-core")) return
    phoneDrag=true
    phOffsetX=e.clientX-container.offsetLeft
    phOffsetY=e.clientY-container.offsetTop
  })
  document.addEventListener("mouseup",()=>{ if(phoneDrag) phoneDrag=false; })
  document.addEventListener("mousemove",(e)=>{
    if(!phoneDrag) return
    container.style.left=(e.clientX-phOffsetX)+"px"
    container.style.top=(e.clientY-phOffsetY)+"px"
  })

}

document.addEventListener("DOMContentLoaded",initIphone)
document.addEventListener("pjax:complete",initIphone)

})();